import { navigateStudioAndAwaitAck } from "../agentSessionChannel.js";
import { getConfig, hasCredentials } from "../config.js";
import { positionalArgs } from "../parseArgs.js";
import { isValidStudioRoute } from "../studioRoutes.js";
const ARGS = [
    { name: "sessionId", format: "uuid" },
    { name: "path" },
];
const args = positionalArgs(ARGS);
const sessionId = args[0];
const path = args[1];
if (!isValidStudioRoute(path)) {
    console.error(`Studio route not allowed: ${path}`);
    process.exit(1);
}
if (!hasCredentials()) {
    console.error("Not authenticated.");
    process.exit(1);
}
const config = getConfig();
if (!config.apiKey) {
    console.error("No API key configured.");
    process.exit(1);
}
const result = await navigateStudioAndAwaitAck({ serviceUrl: config.serviceUrl, apiKey: config.apiKey, sessionId }, path);
if (result.acked) {
    process.stdout.write(`${JSON.stringify({ event: "navigated", sessionId, path })}\n`);
    process.exit(0);
}
else if (result.reason === "blocked") {
    process.stdout.write(`${JSON.stringify({ event: "navigation-blocked", sessionId, path, reason: result.blockedReason })}\n`);
    process.exit(1);
}
else {
    const payload = {
        event: "not-responding",
        sessionId,
    };
    if (result.reason === "push-failed") {
        payload.reason = "push-failed";
    }
    process.stdout.write(`${JSON.stringify(payload)}\n`);
    process.exit(1);
}
